// BUILD PMO UPDATES — promotion plan for Validated portfolio rows.
// Reads Inbox rows + Portfolio programs (flat property_* fields; Bug 23/27).
// Gate: only Record Lifecycle = 'Validated' AND Entity Type = 'portfolio'.
// UPDATE-only: a row whose program name has no match in the Portfolio Register
// is left Validated (NOT promoted, NOT created) so a human can map it.
const inbox = $('Query Inbox Rows').all();
const programs = $('Query Portfolio Programs').all();

// program name (lowercased) -> page id
const progMap = {};
for (const p of programs) {
  const name = String(p.json.property_name || '').trim().toLowerCase();
  if (name) progMap[name] = p.json.id;
}

const ragMap = { green: 'Green', yellow: 'Amber', red: 'Red' };
const today = new Date().toISOString().slice(0, 10);
const out = [];

for (const r of inbox) {
  const j = r.json;
  if (String(j.property_record_lifecycle || '') !== 'Validated') continue;
  if (String(j.property_entity_type || '') !== 'portfolio') continue;

  const program = String(j.property_program || '').trim();
  const progPage = progMap[program.toLowerCase()];
  if (!progPage) continue; // no matching program — leave Validated for manual mapping

  const health = j.property_health_score == null ? null : Number(j.property_health_score);
  const rag = ragMap[String(j.property_risk_level || '').toLowerCase()] || 'Amber';
  const entityKey = String(j.property_entity_key || '');
  const captured = String(j.property_captured_at || '');
  const note = ('Promoted from Integration Inbox · ' + entityKey + ' · health ' + (health == null ? '?' : health) + ' · captured ' + captured).slice(0, 1999);

  out.push({ json: {
    inbox_page_id: j.id,
    program,
    program_page_id: progPage,
    health_score: health,
    rag_status: rag,
    trajectory: String(j.property_trajectory || ''),
    last_review: today,
    status_note: note,
    entity_key: entityKey,
    promoted_at: new Date().toISOString()
  }});
}

if (!out.length) return [{ json: { _empty: true, message: 'No Validated portfolio rows with a matching program to promote.' } }];
return out;
